9792	static int run_agent(ds4_engine *engine, agent_config *cfg) {
9793	    agent_worker worker;
9794	    if (agent_worker_init(&worker, engine, cfg) != 0) return 1;
9795	
9796	    char hist[PATH_MAX];
9797	    const char *home = getenv("HOME");
9798	    if (!home || !home[0]) home = ".";
9799	    snprintf(hist, sizeof(hist), "%s/.ds4_agent_history", home);
9800	    /* The agent uses ANSI scroll regions when possible: model/tool output
9801	     * scrolls above the live linenoise prompt and status footer, so streaming
9802	     * tokens do not require repainting the bottom rows.  Terminals without
9803	     * scroll-region support fall back to the older prompt-below-output path. */
9804	    linenoiseSetMultiLine(1);
9805	    linenoiseHistorySetMaxLen(512);
9806	    linenoiseHistoryLoad(hist);
9807	    agent_completion_worker = &worker;
9808	    linenoiseSetCompletionCallback(agent_switch_completion_callback);
9809	
9810	    agent_status st;
