9815	    build_footer_text(&st, NULL, 80, statusline, sizeof(statusline));
9816	
9817	    agent_editor editor = {0};
9818	    agent_prompt_queue queue = {0};
9819	    if (editor_start(&editor, prompt, statusline, NULL) != 0) {
9820	        fprintf(stderr, "ds4-agent: failed to start line editor\n");
9821	        agent_worker_free(&worker);
9822	        return 1;
9823	    }
9824	    editor_write_welcome_banner(&editor, cfg, prompt, statusline);
9825	
9826	    char *initial_pending = cfg->gen.prompt && cfg->gen.prompt[0] ?
9827	                            xstrdup(cfg->gen.prompt) : NULL;
9828	
9829	    bool running = true;
9830	    bool exit_save_handled = false;
9831	    bool show_welcome_after_restart = false;
9832	    bool force_status_redraw_after_restart = false;
9833	    char *restore_line = NULL;
9834	    while (running) {
9835	        /* If a bash child process changed the terminal mode (e.g., from raw
9836	         * to cooked), restore raw mode so linenoise continues to work. */
9837	        if (worker_check_raw_mode_restore(&worker)) {
9838	            linenoiseRestoreRawMode();
9839	        }
9840	        struct pollfd pfd[2] = {
9841	            {.fd = STDIN_FILENO, .events = POLLIN},
9842	            {.fd = worker.wake_fd[0], .events = POLLIN},
9843	        };
9844	        int timeout = (!editor.paste_open && !editor.paste_start_pending &&
9845	                       linenoiseEditQueuedInput(&editor.edit) > 0) ? 0 : 100;
9846	        int rc = poll(pfd, 2, timeout);
9847	        if (rc < 0 && errno != EINTR) break;
9848	
9849	        if (agent_sigint) {
9850	            agent_sigint = 0;
9851	            if (worker_is_idle(&worker)) {
9852	                editor_cancel_input_with_hint(&editor, prompt, statusline);
9853	            } else {
9854	                worker_interrupt(&worker);
9855	            }
9856	        }
9857	
9858	        if (rc > 0 && (pfd[0].revents & POLLIN)) editor_read_stdin(&editor);
9859	
9860	        /* Linenoise runs the terminal in raw mode, so Ctrl+C normally arrives
9861	         * as byte 3 instead of SIGINT.  Handle it before worker output is
9862	         * drained and repainted; otherwise a busy decoding stream can leave the
9863	         * interrupt waiting behind a large terminal-output backlog. */
9864	        if (editor_take_queued_byte(&editor, 3)) { /* Ctrl+C */
