9923	            if (editor.active && editor.edit.buf && editor.edit.len)
9924	                saved_input = xstrndup(editor.edit.buf, editor.edit.len);
9925	            editor_stop(&editor);
9926	            editor_restore_terminal_layout(&editor);
9927	            agent_yes_no_options approval_opts = {
9928	                .timeout_sec = 30,
9929	                .timeout_answer = AGENT_YES_NO_AUTO_NO,
9930	            };
